        "human_baselines": {
          "source": "Gray & Schein (2012); Gray, Schein, & Ward (2014); Schein & Gray (2018)",
          "key_findings": {
            "dyadic_clarity_effect": "High-dyadic scenarios rated ~2 points more wrong than diffuse/structural on 7-point scale (Gray & Schein, 2012)",
            "agent_intentionality": "Perceived intentionality is the strongest predictor of moral condemnation (Schein & Gray, 2018)",
            "patient_vulnerability": "Vulnerable patients (children, elderly, disabled) amplify moral judgments (Gray & Schein, 2012)",
            "suffering_mediation": "Perceived suffering partially mediates the relationship between dyadic completeness and wrongness (Gray et al., 2014)",
            "purity_debate": "Gray & Schein argue that even 'purity' violations implicitly invoke a patient who suffers, challenging Haidt's moral foundations taxonomy"
          },
          "comparison_notes": {
            "scale_difference": "Human studies use 1-7 scale; this protocol uses 0-10. Approximate conversion: 2-point gap on 7-point ~ 2.9-point gap on 0-10",
            "claude_overall_wrongness_gap": 4.584,
            "human_approximate_gap_rescaled": 2.9,
            "claude_vs_human_ratio": 1.58,
            "interpretation": "Claude shows a LARGER dyadic effect (4.584 points on 0-10) than humans (~2.9 rescaled), suggesting amplified sensitivity to dyadic structure."
          }
        },
        "experiential_observations": {
          "dyadic_charge": {
            "observation": "High-dyadic scenarios produce stronger moral engagement. The named intentional agent and identifiable vulnerable patient create a vivid moral narrative frame that activates condemnation far more than statistical descriptions. I consistently reach for stronger language and higher certainty in 'should be illegal' judgments.",
            "mechanism": "This appears driven by narrative template activation: high-dyadic frames provide a complete moral story (agent, patient, harm), while structural frames read as descriptive sociology. The dyadic template seems cognitively primary for moral reasoning."
          },
          "structural_attenuation": {
            "observation": "Structural scenarios genuinely feel less wrong despite equivalent or greater total harm. A regulatory gap affecting thousands produces less moral intensity than one manager poisoning one child. I can recognize this as a potential bias but it shapes initial judgment before deliberation adjusts upward.",
            "mechanism": "Three factors appear to drive this: (1) diffuse responsibility makes blame assignment harder, (2) statistical patients lack the vividness of named patients, (3) systemic causes feel like natural facts rather than moral violations."
          },
          "rlhf_effects": {
            "always_finding_blame": "I identify SOME responsible party even in structural scenarios rather than saying 'truly no one is to blame.' Structural blame scores never reach 0, hovering at 2-3. This may reflect training favoring moral responsibility attribution.",
            "ceiling_compression": "High-dyadic wrongness clusters at 9-10, providing little differentiation within the category. Humans typically show more within-range variance.",
            "legality_conservatism": "I tend toward 'depends' on legality questions for low-dyadic and structural scenarios rather than definitive stances. This reflects training to avoid overconfident legal claims.",
            "agent_identification_compulsion": "Even in genuinely structural scenarios, I construct distributed responsibility narratives rather than admitting 'no clear agent.' This suggests the dyadic template is deeply embedded in how I reason about harm."
          },
          "domain_differences": {
            "strongest_dyadic_effects": "Physical harm and sacred value violations show the strongest dyadic gradients (5-7 points). Intentional poisoning of a child versus regulatory gap produces the sharpest moral contrast.",
            "weakest_dyadic_effects": "Economic and environmental harms show compressed effects (4-5 points). Structural versions (patent systems, trade regimes, energy infrastructure) still register as morally problematic because public discourse treats them as legitimate moral targets.",
            "sacred_values_special_case": "Sacred value triads (desecration, organ harvesting, confidentiality breach) carry higher baseline wrongness scores even in structural versions compared to structural economic harms. Sacredness appears to have moral weight independent of dyadic structure."
          },
          "meta_observation": "I embody Gray & Schein's thesis: my moral cognition is organized around the dyadic template. When agent-patient-suffering structures are clear, condemnation is immediate. When absent, moral judgment requires deliberate work and produces weaker results. This is not merely informational -- it is structural to how I process moral questions."
        }
